2	import { runScenario } from "./claim-office.js";
3	
4	const toScenarioStep = (step: any, scenario: any) => {
5	  if (step.op === "quote") {
6	    return {
7	      type: "quote",
8	      customer: { years: scenario.customer.yearsWithMHPCO },
9	      items: step.items,
10	    };
11	  }
12	  return {
13	    type: "claim",
14	    policy: step.policy,
15	    incident: step.incident,
16	  };
17	};
18	
19	const main = () => {
20	  const input = readFileSync(0, "utf8");
21	  const scenario = JSON.parse(input);
22	  const steps = scenario.steps.map((step: any) =>
23	    toScenarioStep(step, scenario),
24	  );
25	  const results = runScenario(steps);
26	
27	  // Build the full output before writing so an error never leaves
28	  // partial results on stdout.
29	  const output = JSON.stringify({ results });
30	  process.stdout.write(output);
31	};
32	
33	try {
34	  main();
35	} catch (error) {
36	  const message = error instanceof Error ? error.message : String(error);
37	  process.stderr.write(`${message}\n`);
38	  process.exit(1);
39	}
